const getReshapeContext = `-- name: GetReshapeContext :one
SELECT m.version, m.brightness_offset, m.hue_shift, m.form_seed_delta,
       COALESCE((
           SELECT AVG(ne.embedding)
           FROM memory_links ml
           JOIN embeddings ne ON ne.memory_id = CASE WHEN ml.a_id = m.id THEN ml.b_id ELSE ml.a_id END
           WHERE ml.user_id = m.user_id
             AND (ml.a_id = m.id OR ml.b_id = m.id)
             AND ml.co_activation_count > 0
       ), e.embedding) AS recall_embedding,
       e.embedding AS consolidated_embedding,
       COALESCE((SELECT SUM(ml.co_activation_count) FROM memory_links ml
                 WHERE (ml.a_id = m.id OR ml.b_id = m.id) AND ml.user_id = m.user_id), 0)::int AS co_recall_total,
       m.created_at
FROM memories m JOIN embeddings e ON e.memory_id = m.id
WHERE m.id = $1 AND m.user_id = $2
`

type GetReshapeContextParams struct {
	ID     string `json:"id"`
	UserID string `json:"user_id"`
}

type GetReshapeContextRow struct {
	Version               int32              `json:"version"`
	BrightnessOffset      float32            `json:"brightness_offset"`
	HueShift              float32            `json:"hue_shift"`
	FormSeedDelta         float32            `json:"form_seed_delta"`
	RecallEmbedding       *pgvector.Vector   `json:"recall_embedding"`
	ConsolidatedEmbedding *pgvector.Vector   `json:"consolidated_embedding"`
	CoRecallTotal         int32              `json:"co_recall_total"`
	CreatedAt             pgtype.Timestamptz `json:"created_at"`
}

// PE/strength inputs for one recalled star (spec 23): cumulative reshaping state,
// a server-derived recall-context centroid from co-recalled neighbors, the star's
// own embedding as the consolidated baseline, co-recall total, and created_at. If
// no co-recall context exists, recall_embedding falls back to the star embedding
// so isolated/no-context recalls stay a plain re-ignition.
func (q *Queries) GetReshapeContext(ctx context.Context, arg GetReshapeContextParams) (GetReshapeContextRow, error) {
	row := q.db.QueryRow(ctx, getReshapeContext, arg.ID, arg.UserID)
	var i GetReshapeContextRow
	err := row.Scan(
		&i.Version,
		&i.BrightnessOffset,
		&i.HueShift,
		&i.FormSeedDelta,
		&i.RecallEmbedding,
		&i.ConsolidatedEmbedding,
		&i.CoRecallTotal,
		&i.CreatedAt,
	)
	return i, err
}

const insertMemory = `-- name: InsertMemory :one
INSERT INTO memories (id, user_id, record_id, mood, intensity, fragment_index, fragment_text, valence)
VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
RETURNING id
`

type InsertMemoryParams struct {
	ID            string   `json:"id"`
	UserID        string   `json:"user_id"`
	RecordID      string   `json:"record_id"`
	Mood          *string  `json:"mood"`
	Intensity     *float32 `json:"intensity"`
	FragmentIndex int32    `json:"fragment_index"`
	FragmentText  *string  `json:"fragment_text"`
	Valence       *float32 `json:"valence"`
}

// One fragment star (spec 21): record_id (non-unique FK) links back to the
// original; the fragment's own emotion and text live HERE on the mutable star
// layer (never on the immutable record).
func (q *Queries) InsertMemory(ctx context.Context, arg InsertMemoryParams) (string, error) {
	row := q.db.QueryRow(ctx, insertMemory,
		arg.ID,
		arg.UserID,
		arg.RecordID,
		arg.Mood,
		arg.Intensity,
		arg.FragmentIndex,
		arg.FragmentText,
		arg.Valence,
	)
	var id string
	err := row.Scan(&id)
	return id, err
}

const insertRecord = `-- name: InsertRecord :exec
INSERT INTO records (id, user_id, body, entry_date, mood, intensity, valence, idempotency_key)
VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
`

type InsertRecordParams struct {
	ID             string      `json:"id"`
	UserID         string      `json:"user_id"`
	Body           string      `json:"body"`
	EntryDate      pgtype.Date `json:"entry_date"`
	Mood           *string     `json:"mood"`
	Intensity      *float32    `json:"intensity"`
	Valence        *float32    `json:"valence"`
	IdempotencyKey *string     `json:"idempotency_key"`
}

// The immutable original. No memory_id column (the star points to the record, not
// the reverse). mood/intensity/valence are optional whole-diary user hints
// (spec 21 вҖ” the AI detects per-fragment emotion); idempotency_key is nullable.
func (q *Queries) InsertRecord(ctx context.Context, arg InsertRecordParams) error {
	_, err := q.db.Exec(ctx, insertRecord,
		arg.ID,
		arg.UserID,
		arg.Body,
		arg.EntryDate,
		arg.Mood,
		arg.Intensity,
		arg.Valence,
		arg.IdempotencyKey,
	)
	return err
}

const listArousalInputs = `-- name: ListArousalInputs :many
SELECT m.intensity, m.recall_count, m.last_recalled_at
FROM memories m
WHERE m.user_id = $1
`

