const listDormant = `-- name: ListDormant :many

SELECT m.id AS memory_id, m.mood, m.intensity, m.valence, m.last_recalled_at,
       m.brightness_offset, m.hue_shift, m.form_seed_delta, m.version, m.recall_count, m.abstraction_stage
FROM memories m
WHERE m.user_id = $1
  AND m.last_recalled_at < $2::timestamptz
ORDER BY m.last_recalled_at ASC
`

type ListDormantParams struct {
	UserID string             `json:"user_id"`
	Cutoff pgtype.Timestamptz `json:"cutoff"`
}

type ListDormantRow struct {
	MemoryID         string             `json:"memory_id"`
	Mood             *string            `json:"mood"`
	Intensity        *float32           `json:"intensity"`
	Valence          *float32           `json:"valence"`
	LastRecalledAt   pgtype.Timestamptz `json:"last_recalled_at"`
	BrightnessOffset float32            `json:"brightness_offset"`
	HueShift         float32            `json:"hue_shift"`
	FormSeedDelta    float32            `json:"form_seed_delta"`
	Version          int32              `json:"version"`
	RecallCount      int32              `json:"recall_count"`
	AbstractionStage int16              `json:"abstraction_stage"`
}

// (spec 07) ListRecentForAmbientлҠ” мқҖнҮҙ вҖ” м„ңлІ„ мҡ”мҰҳ-к°җм • мў…н•©(AggregateAmbient)мқ„ м ңкұ°н•ҳкі 
// нҒҙлқјк°Җ лЎңл“ңлҗң лі„(+recall_count)мқҳ Bjork мқём¶ң к°•лҸ„ ОЈ Rм—җм„ң к°җм • мҲңмң„В·arousalмқ„ м§Ғм ‘ нҢҢмғқн•ңлӢӨ.
// (spec 38 change 19) ListStarVectorsByUserлҸ„ мқҖнҮҙ вҖ” relevance(мҡ”мҰҳ нҶ н”Ҫ м •н•©лҸ„)лҘј нҸҗкё°н–ҲлӢӨ(л°қкё°=мһҗкё°-кұ°лҰ¬).
// Long-unrecalled (dormant) stars for search/explorer surfaces. A search aid,
// NOT a delete/filter вҖ” GetUniverse still returns the full graph (constitution В§2). The WHERE
// compares only the last_recalled_at time cutoff (sargable; NO exp()/decay math in SQL вҖ”
// brightness is computed client-side from this same value). The service converts the
// dormancy threshold into `cutoff`. mood/intensity/valence are the fragment's own
// (memories, spec 21; no body sent вҖ” the dormant list renders Star; the original is
// fetched on recall, spec 11). Same column shape as ListMemoriesByUser so it maps to
// the same domain Memory (reshaping state included, spec 23).
func (q *Queries) ListDormant(ctx context.Context, arg ListDormantParams) ([]ListDormantRow, error) {
	rows, err := q.db.Query(ctx, listDormant, arg.UserID, arg.Cutoff)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListDormantRow
	for rows.Next() {
		var i ListDormantRow
		if err := rows.Scan(
			&i.MemoryID,
			&i.Mood,
			&i.Intensity,
			&i.Valence,
			&i.LastRecalledAt,
			&i.BrightnessOffset,
			&i.HueShift,
			&i.FormSeedDelta,
			&i.Version,
			&i.RecallCount,
			&i.AbstractionStage,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

