const listMemoriesByUser = `-- name: ListMemoriesByUser :many
SELECT m.id AS memory_id, m.mood, m.intensity, m.valence, m.last_recalled_at,
       m.brightness_offset, m.hue_shift, m.form_seed_delta, m.version,
       m.record_id, m.fragment_index, m.recall_count, m.abstraction_stage,
       EXISTS (
           SELECT 1 FROM resonances res
           WHERE res.sender_memory_id = m.id OR res.recipient_memory_id = m.id
       ) AS resonant
FROM memories m
WHERE m.user_id = $1
ORDER BY m.created_at, m.fragment_index
`

type ListMemoriesByUserRow struct {
	MemoryID         string             `json:"memory_id"`
	Mood             *string            `json:"mood"`
	Intensity        *float32           `json:"intensity"`
	Valence          *float32           `json:"valence"`
	LastRecalledAt   pgtype.Timestamptz `json:"last_recalled_at"`
	BrightnessOffset float32            `json:"brightness_offset"`
	HueShift         float32            `json:"hue_shift"`
	FormSeedDelta    float32            `json:"form_seed_delta"`
	Version          int32              `json:"version"`
	RecordID         string             `json:"record_id"`
	FragmentIndex    int32              `json:"fragment_index"`
	RecallCount      int32              `json:"recall_count"`
	AbstractionStage int16              `json:"abstraction_stage"`
	Resonant         bool               `json:"resonant"`
}

// Every star for the user, dormant included (no brightness filter вҖ” constitution
// В§2). mood/intensity/valence are the FRAGMENT's own (memories, spec 21) вҖ” no
// records JOIN anymore. The reshaping state (spec 23) rides the same row.
// spec 28: record_id/fragment_index ride along so the client can GROUP stars by
// their original diary (мқјкё° лӢЁмң„ мЎ°л§қ/н•ҳмқҙлқјмқҙнҢ…) without a separate query.
// spec 36: resonant вҖ” мқҙ лі„мқҙ кіөлӘ…(лӢӨлҘё мҡ°мЈјмқҳ лі„)мңјлЎң мқҙм–ҙм ё мһҲлҠ”м§Җ(ліҙлӮё лі„В·мҲҳлқҪмңјлЎң нғңм–ҙлӮң
// лі„ м–‘мӘҪ). resonancesмқҳ м–ҙлҠҗ лҒқм җмқҙл“  мқҙ лі„мқҙл©ҙ true вҶ’ нҒҙлқјк°Җ мқҖмқҖн•ң кіөлӘ… л§Ҳм»ӨлҘј к·ёлҰ°лӢӨ.
func (q *Queries) ListMemoriesByUser(ctx context.Context, userID string) ([]ListMemoriesByUserRow, error) {
	rows, err := q.db.Query(ctx, listMemoriesByUser, userID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListMemoriesByUserRow
	for rows.Next() {
		var i ListMemoriesByUserRow
		if err := rows.Scan(
			&i.MemoryID,
			&i.Mood,
			&i.Intensity,
			&i.Valence,
			&i.LastRecalledAt,
			&i.BrightnessOffset,
			&i.HueShift,
			&i.FormSeedDelta,
			&i.Version,
			&i.RecordID,
			&i.FragmentIndex,
			&i.RecallCount,
			&i.AbstractionStage,
			&i.Resonant,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

