const listRecords = `-- name: ListRecords :many
SELECT r.id AS record_id, r.entry_date, left(r.body, $2::int) AS body_excerpt, count(m.id)::int AS star_count,
       array_remove(array_agg(DISTINCT m.mood), NULL)::text[] AS moods
FROM records r JOIN memories m ON m.record_id = r.id
WHERE r.user_id = $1
GROUP BY r.id, r.entry_date, r.body
ORDER BY r.entry_date DESC
`

type ListRecordsParams struct {
	UserID       string `json:"user_id"`
	ExcerptChars int32  `json:"excerpt_chars"`
}

type ListRecordsRow struct {
	RecordID    string      `json:"record_id"`
	EntryDate   pgtype.Date `json:"entry_date"`
	BodyExcerpt string      `json:"body_excerpt"`
	StarCount   int32       `json:"star_count"`
	Moods       []string    `json:"moods"`
}

// мӣҗліё мқјкё°лЎң лі„ м°ҫкё°(spec 28) м§„мһ… лӘ©лЎқ: нҳём¶ң userмқҳ мӣҗліё мқјкё° + мқјкё°лі„ мЎ°к°Ғ лі„ к°ңмҲҳ.
// recordsлҠ” мқҪкё°л§Ң(н—ҢлІ•1 вҖ” UPDATE/DELETE м—ҶмқҢ). bodyлҠ” м „мІҙк°Җ м•„лӢҲлқј excerpt(left N)л§Ң
// ліҙлӮёлӢӨ(мӣҗліё м „мІҙлҠ” RecallMemory/GetRecord). л°ңм·Ң кёёмқҙ N = values.WayfindingDiaryExcerptChars(change 32 вҖ” 80вҶ’нҷ•лҢҖ,
// DiaryCard нҶ л§ү л°©м§Җ; м—¬м „нһҲ л°ңм·Ңлқј мӣҗліё м „мІҙлҠ” нҡҢмғҒ кІҪлЎң м „мҡ©). entry_date лӮҙлҰјм°ЁмҲң(мөңк·ј мқјкё° лЁјм Җ). user_id = кІ©лҰ¬.
// change 09: moods вҖ” к·ё мқјкё° мЎ°к°Ғ лі„л“Өмқҳ к°җм • facet(мӨ‘ліө м ңкұ°, NULL м ңкұ°). array_agg(DISTINCT)лЎң
// н•ң мқјкё°мқҳ м—¬лҹ¬ мЎ°к°Ғмқҙ к°ҷмқҖ к°җм •мқ„ к°Җм ёлҸ„ н•ң лІҲл§Ң лӮҳмҳӨкІҢ н•ңлӢӨ(мқјкё° лӘ©лЎқ к°җм • н•„н„° мһ…л Ҙ).
func (q *Queries) ListRecords(ctx context.Context, arg ListRecordsParams) ([]ListRecordsRow, error) {
	rows, err := q.db.Query(ctx, listRecords, arg.UserID, arg.ExcerptChars)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListRecordsRow
	for rows.Next() {
		var i ListRecordsRow
		if err := rows.Scan(
			&i.RecordID,
			&i.EntryDate,
			&i.BodyExcerpt,
			&i.StarCount,
			&i.Moods,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const listReknnCandidates = `-- name: ListReknnCandidates :many
SELECT m.id AS memory_id, e.embedding
FROM memories m
JOIN embeddings e ON e.memory_id = m.id
WHERE m.user_id = $1
  AND m.created_at < $2::timestamptz
  AND NOT EXISTS (
    SELECT 1 FROM memory_links ml
    WHERE ml.user_id = m.user_id AND (ml.a_id = m.id OR ml.b_id = m.id)
      AND ml.severed = false AND ml.weight >= $3::float4
  )
`

type ListReknnCandidatesParams struct {
	UserID          string             `json:"user_id"`
	AgeCutoff       pgtype.Timestamptz `json:"age_cutoff"`
	ActiveThreshold float32            `json:"active_threshold"`
}

type ListReknnCandidatesRow struct {
	MemoryID  string           `json:"memory_id"`
	Embedding *pgvector.Vector `json:"embedding"`
}

// мһ¬-KNN нҢЁмҠӨ мһ…л Ҙ: мҳӨлһҳлҗҗкі (created_at < age_cutoff) кұҙк°•н•ң л§ҒнҒ¬к°Җ н•ҳлӮҳлҸ„ м—ҶлҠ”(кі лҰҪмқҙкұ°лӮҳ к°Җм§Җм№ҳкё°лЎң
// лҒҠкёҙ) лі„ + мһ„лІ л”©. "кұҙк°•н•ң л§ҒнҒ¬"лҠ” severed=false мқҙкі  weight вүҘ active_threshold мқё н–ү. мӣҢм»Өк°Җ к°Ғ лі„мқҳ
// мһ„лІ л”©мңјлЎң KnnNearestлҘј лӢӨмӢң лҸҢл Ө к·ёмғҲ мғқкёҙ лӢ®мқҖ кё°м–өкіј л’ӨлҠҰкІҢ мһҮлҠ”лӢӨ(к°Җм§Җм№ҳкё°В·лҒҠк№Җмқҳ м§қ вҖ” мһ¬м—°кІ° м•Ҳм „л§қ).
// мһ„лІ л”© м—ҶлҠ” лі„мқҖ JOINмңјлЎң мһҗм—° м ңмҷё. user_id = isolation.
func (q *Queries) ListReknnCandidates(ctx context.Context, arg ListReknnCandidatesParams) ([]ListReknnCandidatesRow, error) {
	rows, err := q.db.Query(ctx, listReknnCandidates, arg.UserID, arg.AgeCutoff, arg.ActiveThreshold)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListReknnCandidatesRow
	for rows.Next() {
		var i ListReknnCandidatesRow
		if err := rows.Scan(&i.MemoryID, &i.Embedding); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const listStarsForConsolidate = `-- name: ListStarsForConsolidate :many

SELECT m.id AS memory_id, m.last_recalled_at, m.intensity, m.recall_count,
       m.stable_x, m.stable_y, m.stable_z
FROM memories m
WHERE m.user_id = $1
ORDER BY m.created_at, m.fragment_index
`

type ListStarsForConsolidateRow struct {
	MemoryID       string             `json:"memory_id"`
	LastRecalledAt pgtype.Timestamptz `json:"last_recalled_at"`
	Intensity      *float32           `json:"intensity"`
	RecallCount    int32              `json:"recall_count"`
	StableX        *float32           `json:"stable_x"`
	StableY        *float32           `json:"stable_y"`
	StableZ        *float32           `json:"stable_z"`
}

// в”Җв”Җ м•јк°„ кіөкі нҷ”(spec 27) в”Җв”Җ
// м•јк°„ нҢЁмҠӨ мһ…л Ҙ: лі„ лӘ©лЎқ + л°ҳм§ҖлҰ„ к·јмӮ¬ мӣҗмһҗлЈҢ(intensityВ·recall_countВ·last_recalled_at вҖ” change 18
// Bjork R кіөмӢқ)мҷҖ м•Ҳм • мўҢн‘ң мәҗмӢң(stable_*, мһҲмңјл©ҙ лӢӨмқҢ л°Ө force-sim мһ¬м§„мһ… мӢңл“ң). л°ҳм§ҖлҰ„мқҖ мһ¬м•Ҳм •нҷ”/
// мһ¬л¶„л°° мҠӨмҪ”н”„мҷҖ мҡ”м§Җнҷ” лӢЁкі„ нҠёлҰ¬кұ°м—җ м“°кі , last_recalled_atмқҖ Rмқҳ мӢңк°„ н•ӯмқҙлӢӨ. мўҢн‘ңлҠ” к¶Ңмң„ м•„лӢҳ
// (н—ҢлІ•3) вҖ” protoлЎң нҒҙлқјм—җ лӮҳк°Җм§Җ м•ҠлҠ”лӢӨ. user_id = isolation.
func (q *Queries) ListStarsForConsolidate(ctx context.Context, userID string) ([]ListStarsForConsolidateRow, error) {
	rows, err := q.db.Query(ctx, listStarsForConsolidate, userID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListStarsForConsolidateRow
	for rows.Next() {
		var i ListStarsForConsolidateRow
		if err := rows.Scan(
			&i.MemoryID,
			&i.LastRecalledAt,
			&i.Intensity,
			&i.RecallCount,
			&i.StableX,
			&i.StableY,
			&i.StableZ,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const recallMemoryTouch = `-- name: RecallMemoryTouch :exec
UPDATE memories SET last_recalled_at = now(), recall_count = recall_count + 1
WHERE id = $1 AND user_id = $2
`

type RecallMemoryTouchParams struct {
	ID     string `json:"id"`
	UserID string `json:"user_id"`
}

// Re-ignite a star on recall: last_recalled_at = now() AND recall_count += 1 (spec 07 вҖ”
// the cumulative Bjork storage-strength signal). The star is mutable; the original record
// is NOT (constitution В§1). No RETURNING.
func (q *Queries) RecallMemoryTouch(ctx context.Context, arg RecallMemoryTouchParams) error {
	_, err := q.db.Exec(ctx, recallMemoryTouch, arg.ID, arg.UserID)
	return err
}
